if __name__ == '__main__':
    print("Missing character bitmaps (16x16 1bpp, MSB=leftmost):")
    for codepoint, rows in sorted(MISSING_CHARS.items()):
        ch = chr(codepoint)
        hex_str = ", ".join(f"0x{v:04X}" for v in rows)
        print(f"    // {ch} U+{codepoint:04X}")
        print(f"    {{{hex_str}}},")
    print(f"\nTotal: {len(MISSING_CHARS)} characters")